import{_ as e,o as l,c as a,a3 as s}from"./chunks/framework.BTFg6ESq.js";const x=JSON.parse('{"title":"日志与资产管理","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/settings/logs-assets.md","filePath":"user-guide/settings/logs-assets.md","lastUpdated":1778221347000}'),n={name:"user-guide/settings/logs-assets.md"};function r(o,t,d,i,g,h){return l(),a("div",null,[...t[0]||(t[0]=[s(`<h1 id="日志与资产管理" tabindex="-1">日志与资产管理 <a class="header-anchor" href="#日志与资产管理" aria-label="Permalink to &quot;日志与资产管理&quot;">​</a></h1><blockquote><p>日志设置让你精确控制应用的日志记录行为；资产管理则管理所有文件类资产的存储位置。本篇将带你了解如何查询日志、调整日志级别，以及配置资产存储路径和工具可见性。</p></blockquote><hr><h2 id="日志设置" tabindex="-1">日志设置 <a class="header-anchor" href="#日志设置" aria-label="Permalink to &quot;日志设置&quot;">​</a></h2><ol><li>点击标题栏右侧的 ⚙️ 图标进入设置。</li><li>在设置左侧导航栏中点击「日志配置」选项卡。</li></ol><h3 id="日志级别" tabindex="-1">日志级别 <a class="header-anchor" href="#日志级别" aria-label="Permalink to &quot;日志级别&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">级别</th><th style="text-align:left;">说明</th><th style="text-align:left;">适用场景</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>DEBUG (调试)</strong></td><td style="text-align:left;">记录所有日志消息，最详细</td><td style="text-align:left;">问题排查、开发调试</td></tr><tr><td style="text-align:left;"><strong>INFO (信息)</strong></td><td style="text-align:left;">记录常规操作信息</td><td style="text-align:left;">日常使用（推荐）</td></tr><tr><td style="text-align:left;"><strong>WARN (警告)</strong></td><td style="text-align:left;">仅记录警告和错误</td><td style="text-align:left;">生产环境，减少日志量</td></tr><tr><td style="text-align:left;"><strong>ERROR (错误)</strong></td><td style="text-align:left;">仅记录错误信息</td><td style="text-align:left;">最小日志量，仅关注异常</td></tr></tbody></table><blockquote><p><strong>实时生效</strong>：切换日志级别后，系统立即使用新级别记录，无需重启应用。</p></blockquote><h3 id="输出控制" tabindex="-1">输出控制 <a class="header-anchor" href="#输出控制" aria-label="Permalink to &quot;输出控制&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">配置项</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>文件日志</strong></td><td style="text-align:left;">将日志保存到本地文件 <code>appDataDir/logs/app-YYYY-MM-DD.log</code>，按日期分割</td></tr><tr><td style="text-align:left;"><strong>控制台日志</strong></td><td style="text-align:left;">在浏览器开发者控制台（DevTools）中显示日志</td></tr></tbody></table><p>两个开关互不影响，你可以：</p><ul><li>只存文件不看控制台（减少 DevTools 噪音）</li><li>只看控制台不存文件（节省磁盘空间）</li><li>两个都开（开发和排查问题）</li></ul><h3 id="缓冲区配置" tabindex="-1">缓冲区配置 <a class="header-anchor" href="#缓冲区配置" aria-label="Permalink to &quot;缓冲区配置&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">配置项</th><th style="text-align:left;">可选值</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>日志缓冲区大小</strong></td><td style="text-align:left;">500 / 1000 / 2000 / 5000 / 10,000 / 50,000 条</td><td style="text-align:left;">内存中保留的日志条数，超过后删除最早的日志</td></tr><tr><td style="text-align:left;"><strong>文件分割阈值</strong></td><td style="text-align:left;">1MB / 2MB / 5MB / 10MB / 20MB</td><td style="text-align:left;">当日志文件超过此大小，自动分割创建新文件</td></tr></tbody></table><blockquote><p>缓冲区大小仅影响内存中的日志，不影响已保存的日志文件。</p></blockquote><h3 id="日志统计" tabindex="-1">日志统计 <a class="header-anchor" href="#日志统计" aria-label="Permalink to &quot;日志统计&quot;">​</a></h3><p>配置面板中有一个实时更新的统计区域，以卡片形式展示各类别日志条数：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌───────┐ ┌──────┐ ┌──────┐ ┌──────┐ ┌──────┐</span></span>
<span class="line"><span>│  总计 │ │ DEBUG│ │ INFO │ │ WARN │ │ ERROR│</span></span>
<span class="line"><span>│  128  │ │  42  │ │  68  │ │  14  │ │   4  │</span></span>
<span class="line"><span>└───────┘ └──────┘ └──────┘ └──────┘ └──────┘</span></span></code></pre></div><p>每个卡片左侧有颜色标识（主题色/灰色/绿色/橙色/红色），一目了然。</p><h3 id="日志操作" tabindex="-1">日志操作 <a class="header-anchor" href="#日志操作" aria-label="Permalink to &quot;日志操作&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">操作</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>打开日志目录</strong></td><td style="text-align:left;">打开日志文件所在的文件夹（通过 Rust 后端强制绕过前端路径限制）</td></tr><tr><td style="text-align:left;"><strong>导出日志</strong></td><td style="text-align:left;">将内存中的日志保存为 TXT 文件</td></tr><tr><td style="text-align:left;"><strong>清空缓冲区</strong></td><td style="text-align:left;">清空内存中的日志缓冲区，不影响已保存的文件</td></tr><tr><td style="text-align:left;"><strong>测试日志</strong></td><td style="text-align:left;">生成一条测试日志（DEBUG / INFO / WARN / ERROR 各一条），便于验证配置</td></tr></tbody></table><h3 id="当前日志文件" tabindex="-1">当前日志文件 <a class="header-anchor" href="#当前日志文件" aria-label="Permalink to &quot;当前日志文件&quot;">​</a></h3><p>面板底部显示当前正在写入的日志文件完整路径，方便你直接定位：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>appDataDir/logs/app-2025-10-01.log</span></span></code></pre></div><hr><h2 id="资产管理" tabindex="-1">资产管理 <a class="header-anchor" href="#资产管理" aria-label="Permalink to &quot;资产管理&quot;">​</a></h2><p>资产管理位于通用设置面板中，用于配置应用内所有文件类资产的存储位置。</p><blockquote><p><strong>什么是资产？</strong> 资产包括 LLM 聊天中的附件（图片、文档）、OCR 处理的图片、媒体生成器产生的文件等。</p></blockquote><h3 id="路径说明" tabindex="-1">路径说明 <a class="header-anchor" href="#路径说明" aria-label="Permalink to &quot;路径说明&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">项</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>默认路径</strong></td><td style="text-align:left;">应用数据目录下的 <code>assets</code> 文件夹（通过 Rust 后端获取）</td></tr><tr><td style="text-align:left;"><strong>自定义路径</strong></td><td style="text-align:left;">你自己指定的存储位置，为空时使用默认路径</td></tr><tr><td style="text-align:left;"><strong>当前使用路径</strong></td><td style="text-align:left;">实际生效的路径（自定义有值则用自定义，否则用默认）</td></tr></tbody></table><h3 id="操作指南" tabindex="-1">操作指南 <a class="header-anchor" href="#操作指南" aria-label="Permalink to &quot;操作指南&quot;">​</a></h3><p><strong>设置自定义路径</strong>：</p><ol><li>点击「选择目录」按钮</li><li>在弹出的目录选择器中指定新的存储位置</li><li>设置会自动保存并生效</li><li>同时会清除 <code>useAssetManager</code> 中的路径缓存</li></ol><p><strong>重置为默认</strong>：</p><ul><li>如果已经设置了自定义路径，点击「重置为默认」按钮即可恢复</li></ul><p><strong>打开目录</strong>：</p><ul><li>点击「打开目录」按钮快速跳转到当前资产存储位置</li></ul><h3 id="重要说明" tabindex="-1">重要说明 <a class="header-anchor" href="#重要说明" aria-label="Permalink to &quot;重要说明&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">事项</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>仅影响新导入的资产</strong></td><td style="text-align:left;">修改路径后，已有资产<strong>不会</strong>自动迁移到新位置</td></tr><tr><td style="text-align:left;"><strong>需要手动迁移</strong></td><td style="text-align:left;">如果确实需要移动已有资产，请手动操作</td></tr><tr><td style="text-align:left;"><strong>按类型和日期自动分类</strong></td><td style="text-align:left;">资产自动按类型和日期分类存储，如 <code>images/2025-10/</code></td></tr><tr><td style="text-align:left;"><strong>修改后立即生效</strong></td><td style="text-align:left;">下次资源加载时使用新路径</td></tr></tbody></table><hr><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q-日志文件会占用很多磁盘空间吗" tabindex="-1">Q：日志文件会占用很多磁盘空间吗？ <a class="header-anchor" href="#q-日志文件会占用很多磁盘空间吗" aria-label="Permalink to &quot;Q：日志文件会占用很多磁盘空间吗？&quot;">​</a></h3><p>日志模块提供了文件分割和级别控制两种方式管理磁盘占用：</p><ol><li>设置较高的日志级别（如 WARN 或 ERROR）减少日志量</li><li>文件分割阈值设为较小值（如 1MB），超过自动分割，便于清理</li><li>日志按日期分割，你可以定期清理旧的日志文件</li></ol><h3 id="q-修改资产路径后-之前导入的文件还能用吗" tabindex="-1">Q：修改资产路径后，之前导入的文件还能用吗？ <a class="header-anchor" href="#q-修改资产路径后-之前导入的文件还能用吗" aria-label="Permalink to &quot;Q：修改资产路径后，之前导入的文件还能用吗？&quot;">​</a></h3><p><strong>能。</strong> 修改路径只会影响新导入的资产。已有资产仍然在原路径下，应用仍然可以正常访问。如果你希望新旧资产在一起，需要手动搬迁文件。</p><hr><blockquote><p><strong>下一步</strong>：阅读 <a href="./tool-management">工具管理</a>，了解如何控制各工具在主页中的显示和排序。</p></blockquote>`,48)])])}const c=e(n,[["render",r]]);export{x as __pageData,c as default};
